import { state } from '@umbraco-cms/backoffice/external/lit';
import { UmbLitElement } from '@umbraco-cms/backoffice/lit-element';
import { UmbPropertyEditorConfigCollection, UmbPropertyEditorUiElement } from '@umbraco-cms/backoffice/property-editor';

export class FormsFormPickerBaseElement extends UmbLitElement implements UmbPropertyEditorUiElement {

  @state()
  protected allowMultiple: boolean = false;

  @state()
  protected allowedFolders: Array<string> = [];

  @state()
  protected allowedForms: Array<string> = [];

  public set config(config: UmbPropertyEditorConfigCollection | undefined) {
    this.allowedFolders = config?.getValueByAlias('allowedFolders') || [];
    this.allowedForms = config?.getValueByAlias('allowedForms') || [];
  }
}